mapper.insert:
insert into signup values(
signup_seq.nextval, #{id}, #{pw}, #{name}, #{phone}, #{email},
#{oriname}, #{ssn_hash}, #{ssn_enc}, #{ssn_masked}, #{zonecode},
#{address1}, #{address2}, 'PENDING', sysdate, #{sysname}
)

mapper.select:
select * from (
	select signup.*, row_number() over (order by signup_seq desc) rn from signup 

			status = #{status}

	 ) where rn
	between #{start} and #{end}
